def merge_intervals(intervals):
    if not intervals:
        return []

    # Validate and sort intervals by start
    sorted_intervals = []
    for start, end in intervals:
        if start > end:
            raise ValueError("Invalid interval: start cannot be greater than end")
        sorted_intervals.append((start, end))

    sorted_intervals.sort(key=lambda x: x[0])

    # Merge overlapping/touching intervals
    merged = [sorted_intervals[0]]

    for i in range(1, len(sorted_intervals)):
        current = sorted_intervals[i]
        last = merged[-1]

        # Check if current interval overlaps or touches the last merged interval
        if current[0] <= last[1]:
            # Merge by extending the end if needed
            merged[-1] = (last[0], max(last[1], current[1]))
        else:
            merged.append(current)

    return merged
